## Problem1(2.8.6.6)
## Author()
## Institution()
## Language(en-US)

DOCUMENT();

############################################################
# Load Macros
############################################################
loadMacros(
  "PGstandard.pl",
  "PGML.pl",
  "AnswerFormatHelp.pl",
  "PCCmacros.pl",
  "contextFiniteSolutionSets.pl",
  "contextForm.pl",
  "PGcourse.pl",
);
COMMENT('Authored in PreTeXt');

############################################################
# Header
############################################################
TEXT(beginproblem());

############################################################
# PG Setup Code
############################################################
$x = RandomVariableName(type=>'variable');
$m = 1;
$b = non_zero_random(-9,9,1);
$c = list_random(2,3,5,6,7,10,11,13,14,15,17,19);
Context()->variables->are($x=>'Real');
$linear = Formula("$m $x + $b")->reduce;
$left = Formula("($linear)^2");
$leftexpanded = Formula("$m^2 $x^2 + 2*$m*$b $x + ($b)^2")->reduce;
$right = Formula("$c");
Context("FiniteSolutionSets");
$nb = -$b;
$sol1 = Formula("$nb+sqrt($c)");
$sol2 = Formula("$nb-sqrt($c)");
Context()->variables->are($x=>'Real');
$answer = Formula("{$sol1, $sol2}");

############################################################
# Body
############################################################

BEGIN_PGML
Use a square root to solve [`[$left]=[$right]\text{.}`]

[_]{$answer}{25}

END_PGML

############################################################
# Solution
############################################################

BEGIN_PGML_SOLUTION
Using the square root property:

[```\newcommand{\amp}{&}
\begin{aligned}
[$linear]\amp=\sqrt{[$c]}\amp\amp\text{or}\amp [$linear]\amp=-\sqrt{[$c]}\\
[$x]\amp=[$sol1]\amp\amp\text{or}\amp [$x]\amp=[$sol2]
\end{aligned}
```]

So the solution set is [`[$answer]\text{.}`]

END_PGML_SOLUTION

############################################################
# End Problem
############################################################

ENDDOCUMENT();
